const checkpoints = [];

function calcDistanceMilesFromZip(obj, search_zip) {
  if (!obj || !obj.zip_code || !search_zip) return null;
  if (obj.zip_code === search_zip) return 0;
  const objPrefix = String(obj.zip_code).slice(0, 3);
  const searchPrefix = String(search_zip).slice(0, 3);
  if (objPrefix === searchPrefix) {
    return 2;
  }
  return 9999;
}

function parseTimeToMinutes(timeStr) {
  if (!timeStr) return null;
  const parts = timeStr.split(':');
  const h = parseInt(parts[0], 10);
  const m = parts.length > 1 ? parseInt(parts[1], 10) : 0;
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
}

const savedLists = JSON.parse(localStorage.getItem('saved_lists') || '[]');
const savedItems = JSON.parse(localStorage.getItem('saved_list_items') || '[]');
const places = JSON.parse(localStorage.getItem('places') || '[]');
const hours = JSON.parse(localStorage.getItem('place_operating_hours') || '[]');

const targetList = savedLists.find(l => (l.name || '').toLowerCase() === 'family dinner friday');

let qualifyingCount = 0;
if (targetList) {
  const listItems = savedItems.filter(it => it.listId === targetList.id && it.item_type === 'place');
  listItems.forEach(it => {
    const p = places.find(pl => pl.id === it.item_id);
    if (!p) return;
    if (p.category_id !== 'restaurants_food' || p.subcategory !== 'restaurant') return;
    const dist = calcDistanceMilesFromZip(p, '12345');
    if (dist == null || dist > 3) return;
    if ((p.rating || 0) < 4.5) return;
    if (p.average_price_per_person == null || p.average_price_per_person > 20) return;
    if (!p.is_family_friendly) return;
    const day = 'friday';
    const placeHours = hours.filter(h => h.placeId === p.id && h.day_of_week === day && !h.is_closed);
    if (!placeHours.length) return;
    const targetMinutes = parseTimeToMinutes('19:00');
    const openOk = placeHours.some(h => {
      const o = parseTimeToMinutes(h.open_time);
      const c = parseTimeToMinutes(h.close_time);
      return o != null && c != null && o <= targetMinutes && c >= targetMinutes;
    });
    if (!openOk) return;
    qualifyingCount += 1;
  });
}

checkpoints.push({ passed: !!(targetList && qualifyingCount >= 1), weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

