const comparedIds = JSON.parse(localStorage.getItem('task2_comparedPlumberIds') || '[]');
const places = JSON.parse(localStorage.getItem('places') || '[]');
const savedLists = JSON.parse(localStorage.getItem('saved_lists') || '[]');
const savedItems = JSON.parse(localStorage.getItem('saved_list_items') || '[]');

const qualifyingPlumbers = places.filter(p => {
  if (p.category_id !== 'home_services' || p.subcategory !== 'plumber') return false;
  if (!p.is_24_7_emergency) return false;
  if ((p.rating || 0) < 4.0) return false;
  if (p.call_out_fee == null || p.call_out_fee > 100) return false;
  const dist = calcDistanceMilesFromZip(p, '12345');
  if (dist == null || dist > 10) return false;
  return true;
});

const comparedQualifying = Array.isArray(comparedIds)
  ? qualifyingPlumbers.filter(p => comparedIds.includes(p.id))
  : [];

checkpoints.push({
  passed: comparedQualifying.length >= 2,
  weight: 0.3
});

const emergencyList = savedLists.find(l => (l.name || '').toLowerCase() === 'emergency contacts');
let qualifyingInList = [];
if (emergencyList) {
  const listItems = savedItems.filter(it => it.listId === emergencyList.id && it.item_type === 'place');
  qualifyingInList = listItems
    .map(it => places.find(p => p.id === it.item_id))
    .filter(p => p && qualifyingPlumbers.some(q => q.id === p.id));
}

checkpoints.push({
  passed: !!(emergencyList && qualifyingInList.length >= 1),
  weight: 0.3
});

let cheapest = null;
qualifyingPlumbers.forEach(p => {
  if (p.call_out_fee == null) return;
  if (!cheapest || p.call_out_fee < cheapest.call_out_fee) {
    cheapest = p;
  }
});

const hasCheapestInList = !!(cheapest && qualifyingInList.some(p => p.id === cheapest.id));

checkpoints.push({
  passed: hasCheapestInList,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

