function getNextSaturdayDate(baselineDateStr) {
  const d = new Date(baselineDateStr + 'T00:00:00');
  if (isNaN(d.getTime())) return null;
  const day = d.getUTCDay();
  const target = 6; // Saturday
  const delta = (target - day + 7) % 7;
  const sat = new Date(d.getTime() + delta * 24 * 60 * 60 * 1000);
  return sat.toISOString().slice(0, 10);
}

const savedLists = JSON.parse(localStorage.getItem('saved_lists') || '[]');
const savedItems = JSON.parse(localStorage.getItem('saved_list_items') || '[]');
const events = JSON.parse(localStorage.getItem('events') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineDate = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const saturdayDate = getNextSaturdayDate(baselineDate);

const weekendList = savedLists.find(l => (l.name || '').toLowerCase() === 'weekend plan');

let qualifyingSaved = [];
if (weekendList && saturdayDate) {
  const listItems = savedItems.filter(it => it.listId === weekendList.id && it.item_type === 'event');
  listItems.forEach(it => {
    const e = events.find(ev => ev.id === it.item_id);
    if (!e) return;
    if (e.event_type !== 'events') return;
    if (!e.start_datetime) return;
    const dStr = new Date(e.start_datetime).toISOString().slice(0, 10);
    if (dStr !== saturdayDate) return;
    const dist = calcDistanceMilesFromZip(e, '12345');
    if (dist == null || dist > 5) return;
    if (!(e.is_free || e.price === 0)) return;
    const start = new Date(e.start_datetime);
    const end = e.end_datetime ? new Date(e.end_datetime) : null;
    if (isNaN(start.getTime())) return;
    const sM = start.getHours() * 60 + start.getMinutes();
    const eM = end && !isNaN(end.getTime()) ? end.getHours() * 60 + end.getMinutes() : sM;
    const startFilter = parseTimeToMinutes('13:00');
    const endFilter = parseTimeToMinutes('18:00');
    if (eM < startFilter || sM > endFilter) return;
    if (!qualifyingSaved.some(q => q.id === e.id)) {
      qualifyingSaved.push(e);
    }
  });
}

checkpoints.push({
  passed: !!(weekendList && qualifyingSaved.length >= 1),
  weight: 0.5
});

checkpoints.push({
  passed: !!(weekendList && qualifyingSaved.length >= 2),
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

