function addDays(dateStr, days) {
  const d = new Date(dateStr + 'T00:00:00');
  if (isNaN(d.getTime())) return null;
  const d2 = new Date(d.getTime() + days * 24 * 60 * 60 * 1000);
  return d2.toISOString().slice(0, 10);
}

const messages = JSON.parse(localStorage.getItem('organizer_messages') || '[]');
const events = JSON.parse(localStorage.getItem('events') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineDate = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const startDate = baselineDate;
const endDate = addDays(baselineDate, 31);

let qualifyingMessages = [];

messages.forEach(msg => {
  const ev = events.find(e => e.id === msg.eventId);
  if (!ev) return;
  if (ev.event_type !== 'volunteering') return;
  if (ev.cause !== 'environment') return;
  if (!ev.start_datetime) return;
  const dStr = new Date(ev.start_datetime).toISOString().slice(0, 10);
  if (dStr < startDate || dStr > endDate) return;
  const dist = calcDistanceMilesFromZip(ev, '12345');
  if (dist == null || dist > 15) return;
  if (ev.spots_remaining == null || ev.spots_remaining < 10) return;
  qualifyingMessages.push(msg);
});

checkpoints.push({
  passed: qualifyingMessages.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

