const groups = JSON.parse(localStorage.getItem('groups') || '[]');
const memberships = JSON.parse(localStorage.getItem('group_memberships') || '[]');
const events = JSON.parse(localStorage.getItem('events') || '[]');
const rsvps = JSON.parse(localStorage.getItem('event_rsvps') || '[]');
const metadata = JSON.parse(localStorage.getItem('_metadata') || 'null');
const baselineDate = metadata && metadata.baselineDate ? metadata.baselineDate : '2026-03-03';
const now = new Date(baselineDate + 'T00:00:00');

const qualifyingGroups = groups.filter(g => {
  if ((g.focus || '').toLowerCase() !== 'yoga') return false;
  const level = g.experience_level || 'all_levels';
  if (!(level === 'beginner' || level === 'all_levels')) return false;
  const pattern = g.meeting_pattern || null;
  if (pattern && pattern !== 'weekday_evenings' && pattern !== 'variable') return false;
  const dist = calcDistanceMilesFromZip(g, '12345');
  if (dist == null || dist > 10) return false;
  return true;
});

const memberQualGroups = qualifyingGroups.filter(g =>
  memberships.some(m => m.groupId === g.id && m.status === 'member')
);

checkpoints.push({
  passed: memberQualGroups.length >= 1,
  weight: 0.5
});

let hasRsvpNextSession = false;
memberQualGroups.forEach(g => {
  const groupEvents = events
    .filter(e =>
      e.associated_group_id === g.id &&
      e.event_type === 'group_session' &&
      e.status === 'scheduled' &&
      e.start_datetime &&
      !isNaN(new Date(e.start_datetime).getTime()) &&
      new Date(e.start_datetime) >= now
    )
    .sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));

  if (!groupEvents.length) return;
  const nextEvent = groupEvents[0];
  const rsvp = rsvps.find(r => r.eventId === nextEvent.id);
  if (rsvp && rsvp.status === 'going') {
    hasRsvpNextSession = true;
  }
});

checkpoints.push({
  passed: hasRsvpNextSession,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

